def divide(a, b):
    if b == 0:
        raise ValueError('Divide by zero')
    return a / b

examples.toCode:
fn divide(a: f64, b: f64) -> Result<f64, String> {
    if b == 0.0 {
        return Err(String::from("Divide by zero"));
    }
    Ok(a / b)
}

enum Status {
    Ok,
    Error,
}

fn handle_status(status: Status) -> u32 {
    match status {
        Status::Ok => 200,
        Status::Error => 500,
    }
}
